The melting point of mercury is $-39^\circ$C.

\textbf{Part A} Choose an inequality to represent the temperatures at which mercury will be in a liquid state (above its melting point).

\begin{tabular}{ll}
a. & $x \ge -39$ \\
b. & $x \le -39$ \\
c. & $x > -39$ \\
d. & $x < -39$
\end{tabular}

\textbf{Part B} Graph the inequality.

\begin{tikzpicture}
\draw[->] (0,0) -- (9.5,0);
\draw[<-] (-0.5,0) -- (0,0);
\foreach \x/\label in {0/-90, 0.5/-80, 1/-70, 1.5/-60, 2/-50, 2.5/-40, 3/-30, 3.5/-20, 4/-10, 4.5/0, 5/10, 5.5/20, 6/30, 6.5/40, 7/50, 7.5/60, 8/70, 8.5/80, 9/90} {
  \draw (\x,0.1) -- (\x,-0.1);
  \node[below] at (\x,-0.1) {\tiny \label};
}
\end{tikzpicture}
